sql:
SELECT player_name
FROM players
WHERE matches_played = (SELECT MAX(matches_played) FROM players);

external_knowledge:
Recent performances refer to the most recent matches played by each player; 
Recent batting and bowling averages are calculated based on the most recent matches; 
The same recent match for both batting and bowling means the most recent match where the player both batted and bowled.

sql:
SELECT player_name
FROM players
WHERE runs = (
  SELECT MAX(runs)
  FROM players
);

SELECT average AS highest_average
FROM players
WHERE player_id = 1;

SELECT T.team_name
FROM teams T
JOIN team_standings S ON T.team_id = S.team_id
WHERE S.points = (
  SELECT MAX(points) FROM team_standings
);
